    24→// The base class of the stream listener. It owns listener filter handling of active sockets.
    25→// After the active socket passes all the listener filters, a server connection is created. The
    26→// derived listener must override ``newActiveConnection`` to take the ownership of that server
    27→// connection.
    28→// TODO(lambdai): Refactor the listener filter test cases to adopt this class.
    29→class ActiveStreamListenerBase : public ActiveListenerImplBase,
    30→                                 protected Logger::Loggable<Logger::Id::conn_handler> {
    31→public:
    32→  ActiveStreamListenerBase(Network::ConnectionHandler& parent, Event::Dispatcher& dispatcher,
    33→                           Network::ListenerPtr&& listener, Network::ListenerConfig& config);
    34→  static void emitLogs(Network::ListenerConfig& config, StreamInfo::StreamInfo& stream_info);
    35→
    36→  Event::Dispatcher& dispatcher() { return dispatcher_; }
    37→
    38→  /**
    39→   * Schedule to remove and destroy the active connections which are not tracked by listener
    40→   * config. Caution: The connection are not destroyed yet when function returns.
    41→   */
    42→  void onFilterChainDraining(
    43→      const std::list<const Network::FilterChain*>& draining_filter_chains) override {
    44→    // Need to recover the original deleting state.
    45→    const bool was_deleting = is_deleting_;
    46→    is_deleting_ = true;
    47→    for (const auto* filter_chain : draining_filter_chains) {
    48→      removeFilterChain(filter_chain);
    49→    }
    50→    is_deleting_ = was_deleting;
    51→  }
    52→
    53→  virtual void incNumConnections() PURE;
    54→  virtual void decNumConnections() PURE;
    55→
    56→  /**
    57→   * Create a new connection from a socket accepted by the listener.
    58→   */
    59→  void newConnection(Network::ConnectionSocketPtr&& socket,
    60→                     std::unique_ptr<StreamInfo::StreamInfo> stream_info);
    61→
    62→  /**
    63→   * Remove the socket from this listener. Should be called when the socket passes the listener
    64→   * filter.
    65→   * @return std::unique_ptr<ActiveTcpSocket> the exact same socket in the parameter but in the
    66→   * state that not owned by the listener.
    67→   */
    68→  std::unique_ptr<ActiveTcpSocket> removeSocket(ActiveTcpSocket&& socket) {
    69→    return socket.removeFromList(sockets_);
    70→  }
    71→
    72→  /**
    73→   * @return const std::list<std::unique_ptr<ActiveTcpSocket>>& the sockets going through the
    74→   * listener filters.
    75→   */
    76→  const std::list<std::unique_ptr<ActiveTcpSocket>>& sockets() const { return sockets_; }
    77→
    78→  /**
    79→   * Schedule removal and destruction of all active connections owned by a filter chain.
    80→   */
    81→  virtual void removeFilterChain(const Network::FilterChain* filter_chain) PURE;
    82→
    83→  virtual Network::BalancedConnectionHandlerOptRef
    84→  getBalancedHandlerByAddress(const Network::Address::Instance& address) PURE;
    85→
    86→  void onSocketAccepted(std::unique_ptr<ActiveTcpSocket> active_socket) {
    87→    // Create and run the filters
    88→    if (config_->filterChainFactory().createListenerFilterChain(*active_socket)) {
    89→      active_socket->startFilterChain();
    90→    } else {
    91→      // If create listener filter chain failed, it means the listener is missing
    92→      // config due to the ECDS. Then close the connection directly.
    93→      active_socket->socket().close();
    94→      ASSERT(active_socket->isEndFilterIteration());
    95→    }
    96→
    97→    // Move active_socket to the sockets_ list if filter iteration needs to continue later.
    98→    // Otherwise we let active_socket be destructed when it goes out of scope.
    99→    if (!active_socket->isEndFilterIteration()) {
   100→      active_socket->startTimer();
   101→      LinkedList::moveIntoListBack(std::move(active_socket), sockets_);
   102→    } else {
   103→      if (!active_socket->connected()) {
   104→        // If active_socket is about to be destructed, emit logs if a connection is not created.
   105→        if (active_socket->streamInfo() != nullptr) {
   106→          emitLogs(*config_, *active_socket->streamInfo());
   107→        } else {
   108→          // If the active_socket is not connected, this socket is not promoted to active
   109→          // connection. Thus the stream_info_ is owned by this active socket.
   110→          ENVOY_BUG(active_socket->streamInfo() != nullptr,
   111→                    "the unconnected active socket must have stream info.");
   112→        }
   113→      }
   114→    }
   115→  }
   116→
   117→  // Below members are open to access by ActiveTcpSocket.
   118→  Network::ConnectionHandler& parent_;
   119→  const std::chrono::milliseconds listener_filters_timeout_;
   120→  const bool continue_on_listener_filters_timeout_;
   121→
   122→protected:
   123→  /**
   124→   * Create the active connection from server connection. This active listener owns the created
   125→   * active connection.
   126→   *
