      : stats_({ALL_LISTENER_STATS(POOL_COUNTER(config->listenerScope()),
                                   POOL_GAUGE(config->listenerScope()),
                                   POOL_HISTOGRAM(config->listenerScope()))}),
        per_worker_stats_({ALL_PER_HANDLER_LISTENER_STATS(
